targetCode.css:
body {
  font-family: system-ui, sans-serif;
  margin: 0;
  background: #f4f7f5;
}

.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: #17201e;
  color: white;
  padding: 14px 24px;
}

.logo {
  font-weight: 800;
}

ul {
  list-style: none;
  margin: 0;
